import 'package:flutter_fractals/features/auto_explore/auto_explore_runtime_state.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreRuntimeState', () {
    test('allows scheduling only while auto-explore owns motion', () {
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).canScheduleZoomLeg,
        isTrue,
      );

      for (final state in [
        const AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: true,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
      ]) {
        expect(state.canScheduleZoomLeg, isFalse);
        expect(state.shouldInterruptAnimation, isTrue);
      }
    });

    test('keeps user-correction pause as an explicit motion blocker', () {
      final yieldedWithoutInteraction = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: false,
        pausedByUserCorrection: true,
      );

      expect(yieldedWithoutInteraction.canScheduleZoomLeg, isFalse);
      expect(yieldedWithoutInteraction.shouldInterruptAnimation, isTrue);
    });

    test('adopts continuous interaction end only after a matching start', () {
      const matchingStart = AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: true,
        pausedByUserCorrection: true,
      );

      expect(matchingStart.hasContinuousInteractionYield, isTrue);
      expect(matchingStart.canAdoptContinuousInteractionEnd, isTrue);

      for (final state in [
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: true,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: false,
        ),
      ]) {
        expect(state.hasContinuousInteractionYield, isFalse);
        expect(state.canAdoptContinuousInteractionEnd, isFalse);
      }
    });

    test('exposes replayable toggle transitions', () {
      expect(
        const AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).toggleTransition,
        AutoExploreToggleTransition.start,
      );
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).toggleTransition,
        AutoExploreToggleTransition.pause,
      );
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).toggleTransition,
        AutoExploreToggleTransition.resume,
      );
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: true,
        ).toggleTransition,
        AutoExploreToggleTransition.resume,
      );
    });

    test('gates one-shot corrections while continuous gestures own motion', () {
      final idleAutoExplore = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: false,
        pausedByUserCorrection: false,
      );
      final continuousGesture = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: true,
        pausedByUserCorrection: true,
      );

      expect(
        AutoExploreUserCorrectionPolicy.shouldAdoptOneShotCorrection(
          idleAutoExplore,
        ),
        isTrue,
      );
      expect(
        AutoExploreUserCorrectionPolicy.shouldAdoptOneShotCorrection(
          continuousGesture,
        ),
        isFalse,
      );
    });

    test('characterizes user-correction pause as armed auto-explore only', () {
      expect(
        () => AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
        throwsAssertionError,
      );
      expect(
        () => AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
        throwsAssertionError,
      );
    });
  });
}

import 'dart:math' as math;

import 'package:flutter/foundation.dart';

const double _mandelbrotDf2LowerThreshold = 5e6;
const double _mandelbrotDf2UpperThreshold = 1e12;
const double _escapeTimeCpuFallbackThreshold = 1e9;
const double _defaultCpuFallbackThreshold = 1e7;

/// Describes the precision boundaries for one fractal module.
@immutable
class DeepZoomThresholds {
  final double cpuFallbackZoom;
  final double? doubleFloatLowerZoom;
  final double? doubleFloatUpperZoom;

  const DeepZoomThresholds({
    required this.cpuFallbackZoom,
    this.doubleFloatLowerZoom,
    this.doubleFloatUpperZoom,
  })  : assert(
          (doubleFloatLowerZoom == null) == (doubleFloatUpperZoom == null),
          'double-float ranges must provide both lower and upper bounds',
        ),
        assert(
          (doubleFloatLowerZoom ?? double.negativeInfinity) <
              (doubleFloatUpperZoom ?? double.infinity),
          'double-float lower bound must be below upper bound',
        ),
        assert(
          (doubleFloatUpperZoom ?? double.negativeInfinity) <= cpuFallbackZoom,
          'double-float range must end no later than CPU fallback',
        );

  bool get supportsDoubleFloat => doubleFloatLowerZoom != null;

  bool shouldUseCpuFallback(double zoom) => zoom >= cpuFallbackZoom;

  bool shouldUseDoubleFloat(double zoom) {
    final lower = doubleFloatLowerZoom;
    final upper = doubleFloatUpperZoom;
    if (lower == null || upper == null) return false;
    return zoom >= lower && zoom < upper;
  }
}

/// Replayable precision routing decision for a module/zoom sample.
///
/// Renderer code needs CPU fallback and double-float eligibility to agree on
/// the same threshold snapshot. Keeping both booleans with their source
/// thresholds exposes that data-flow instead of recomputing partial decisions
/// at separate call sites.
@immutable
class DeepZoomPrecisionDecision {
  final String moduleId;
  final double zoom;
  final DeepZoomThresholds thresholds;

  const DeepZoomPrecisionDecision({
    required this.moduleId,
    required this.zoom,
    required this.thresholds,
  });

  bool get shouldUseCpuFallback => thresholds.shouldUseCpuFallback(zoom);
  bool get shouldUseDoubleFloat => thresholds.shouldUseDoubleFloat(zoom);
  double get cpuFallbackZoom => thresholds.cpuFallbackZoom;
}

/// Decides when GPU precision is likely insufficient at deep zoom.
///
/// ## Float32 precision analysis
///
/// GPU fragment shaders use float32 arithmetic (~7 significant digits,
/// mantissa ≈ 2^-24 ≈ 6e-8).
///
/// The coordinate span per pixel is: span_per_px = fractal_range / (zoom * resolution)
///   For a 1080p display and a fractal range of ~3 units:
///     span_per_px = 3 / (zoom * 1920) ≈ 1.6e-3 / zoom
///
/// Float32 artifacts appear when the per-pixel span drops below the
/// representable precision at the current center offset. In the worst case
/// (center near origin, no cancellation) this is roughly:
///     artifact threshold zoom ≈ 1.6e-3 / 6e-8 ≈ 2.7e4  ... but only at
///     an offset of ~1.0 unit from origin. Deep in the Mandelbrot boundary
///     where |c| ≈ 2, precision is consumed faster (≈ 1e4–1e5).
///     With the standard center at (0,0) or a well-normalized fractal,
///     artifacts are not visible until zoom ≈ 1e6–1e8.
///
/// Our shaders perform double-width emulation via paired float32 values
/// (see shader uniform layout) for a subset of fractals, extending usable
/// GPU range to ~1e12 before requiring CPU.
///
/// ## Conservative threshold policy
///
/// These thresholds are intentionally HIGH so GPU is used as long as
/// possible. The CPU fallback is a correctness escape hatch, not a
/// performance choice — it is significantly slower and disables GPU effects.
///
/// Raise these thresholds if you observe visible precision artifacts before
/// the switch; lower them only if tested on a low-DPI device where artifacts
/// appear earlier.
@immutable
class DeepZoomPrecisionPolicy {
  /// Maximum iterations we send to GPU shaders for real-time rendering.
  ///
  /// Most escape-time shaders clamp around this value already; keeping the
  /// cap centralized avoids overdriving slower devices at extreme zoom.
  static const int gpuMaxIterations = 2000;

  /// Per-module GPU→CPU fallback thresholds.
  ///
  /// For mandelbrot, the CPU fallback threshold is pushed to the df2 upper
  /// bound because the double-float shader [mandelbrot_df2.frag] covers the
  /// intermediate zoom range before CPU fallback.
  ///
  /// Other escape-time fractals still use float32 GPU up to their threshold,
  /// then fall back to CPU (no df2 variant available yet).
  static const Map<String, DeepZoomThresholds> _moduleThresholds = {
    // Mandelbrot: df2 shader covers zoom [5e6, 1e12), so CPU fallback only
    // kicks in at 1e12 (the df2 upper bound).
    'mandelbrot': DeepZoomThresholds(
      cpuFallbackZoom: _mandelbrotDf2UpperThreshold,
      doubleFloatLowerZoom: _mandelbrotDf2LowerThreshold,
      doubleFloatUpperZoom: _mandelbrotDf2UpperThreshold,
    ),
    // Julia & related escape-time fractals: GPU precision degrades sooner,
    // so switch to CPU around ~1e9.
    'julia': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'celtic': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'buffalo': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'burning_ship': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'tricorn': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot3': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot4': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot5': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'phoenix': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
  };

  /// Default threshold for any fractal type not listed above.
  /// Simple orbit fractals and non-escape-time types lose precision more
  /// slowly; 1e7 is a conservative upper bound for float32 at 1080p.
  static const DeepZoomThresholds _defaultThresholds = DeepZoomThresholds(
    cpuFallbackZoom: _defaultCpuFallbackThreshold,
  );

  /// Number of consecutive evaluations above the zoom threshold required
  /// before committing to CPU fallback. Prevents rapid GPU↔CPU flicker
  /// when zooming near the boundary.
  static const int _hysteresisFrames = 2;

  const DeepZoomPrecisionPolicy();

  /// Returns true when GPU precision is insufficient at the given zoom.
  ///
  /// Pure, stateless evaluation — callers that want hysteresis should
  /// use [DeepZoomHysteresis] to track frame counts.
  bool shouldUseCpuFallback({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseCpuFallback;
  }

  DeepZoomThresholds thresholdsFor(String moduleId) =>
      _moduleThresholds[moduleId] ?? _defaultThresholds;

  DeepZoomPrecisionDecision decisionFor({
    required String moduleId,
    required double zoom,
  }) {
    return DeepZoomPrecisionDecision(
      moduleId: moduleId,
      zoom: zoom,
      thresholds: thresholdsFor(moduleId),
    );
  }

  double thresholdFor(String moduleId) =>
      thresholdsFor(moduleId).cpuFallbackZoom;

  /// Returns true when the double-float shader should be used for [moduleId].
  ///
  /// Currently only mandelbrot has a df2 variant. The range is exclusive of
  /// the CPU fallback threshold.
  bool shouldUseDoubleFloat({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseDoubleFloat;
  }

  int get hysteresisFrames => _hysteresisFrames;

  /// Auto-scales iteration count with zoom depth for GPU rendering.
  ///
  /// Keeps shallow zoom responsive while increasing detail as zoom grows,
  /// reducing under-iteration artifacts in deep zoom.
  ///
  /// Scaling curve:
  /// - zoom <= 1: unchanged
  /// - zoom > 1: base * (1 + 0.35 * log10(zoom))
  /// - clamped to [4, gpuMaxIterations]
  int scaledGpuIterations({
    required int baseIterations,
    required double zoom,
  }) {
    final safeBase = baseIterations.clamp(4, gpuMaxIterations);
    final depth = _zoomDepthLog10(zoom);
    if (depth == 0.0) return safeBase;

    final factor = 1.0 + 0.35 * depth;
    final scaled = (safeBase * factor).round();
    return scaled.clamp(4, gpuMaxIterations);
  }
}

double _zoomDepthLog10(double zoom) {
  if (zoom.isNaN || zoom <= 1.0) return 0.0;
  if (zoom.isInfinite) return 30.0;
  return (math.log(zoom) / math.ln10).clamp(0.0, 30.0);
}

/// Replayable state for one GPU→CPU deep-zoom hysteresis streak.
///
/// Keeping the transition pure makes the hidden state/order dependence visible:
/// streaks are scoped to one module, below-threshold samples reset immediately,
/// and CPU fallback activates only after enough consecutive above-threshold
/// samples for the same module.
@immutable
class DeepZoomHysteresisState {
  final String? moduleId;
  final int aboveThresholdCount;
  final bool cpuActive;

  const DeepZoomHysteresisState({
    required this.moduleId,
    required this.aboveThresholdCount,
    required this.cpuActive,
  });

  const DeepZoomHysteresisState.initial()
      : moduleId = null,
        aboveThresholdCount = 0,
        cpuActive = false;

  DeepZoomHysteresisState next({
    required String nextModuleId,
    required bool overThreshold,
    required int activationFrames,
  }) {
    assert(activationFrames > 0, 'activationFrames must be positive');
    final sameModule = moduleId == nextModuleId;
    final currentCount = sameModule ? aboveThresholdCount : 0;

    if (!overThreshold) {
      return DeepZoomHysteresisState(
        moduleId: nextModuleId,
        aboveThresholdCount: 0,
        cpuActive: false,
      );
    }

    final nextCount = currentCount + 1;
    return DeepZoomHysteresisState(
      moduleId: nextModuleId,
      aboveThresholdCount: nextCount,
      cpuActive: nextCount >= activationFrames,
    );
  }
}

/// Stateful hysteresis filter for GPU→CPU deep-zoom transitions.
///
/// Wraps [DeepZoomPrecisionPolicy] and requires [policy.hysteresisFrames]
/// consecutive above-threshold evaluations before reporting CPU needed.
/// Drops back to GPU immediately when zoom falls below threshold.
class DeepZoomHysteresis {
  final DeepZoomPrecisionPolicy policy;
  DeepZoomHysteresisState _state = const DeepZoomHysteresisState.initial();

  DeepZoomHysteresis({this.policy = const DeepZoomPrecisionPolicy()});

  DeepZoomHysteresisState get state => _state;

  /// Call this on every zoom change. Returns true if CPU fallback is warranted.
  bool update({required String moduleId, required double zoom}) {
    final overThreshold = policy.shouldUseCpuFallback(
      moduleId: moduleId,
      zoom: zoom,
    );

    _state = _state.next(
      nextModuleId: moduleId,
      overThreshold: overThreshold,
      activationFrames: policy.hysteresisFrames,
    );
    return _state.cpuActive;
  }

  void reset() {
    _state = const DeepZoomHysteresisState.initial();
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

void main() {
  const policy = DeepZoomPrecisionPolicy();

  group('DeepZoomPrecisionPolicy.thresholdsFor', () {
    test('exposes contiguous Mandelbrot df2 to CPU fallback boundaries', () {
      final thresholds = policy.thresholdsFor('mandelbrot');

      expect(thresholds.supportsDoubleFloat, isTrue);
      expect(thresholds.doubleFloatLowerZoom, 5e6);
      expect(thresholds.doubleFloatUpperZoom, thresholds.cpuFallbackZoom);
      expect(thresholds.shouldUseDoubleFloat(1e11), isTrue);
      expect(
        thresholds.shouldUseDoubleFloat(thresholds.cpuFallbackZoom),
        isFalse,
      );
      expect(
        thresholds.shouldUseCpuFallback(thresholds.cpuFallbackZoom),
        isTrue,
      );
    });

    test('exposes default thresholds without a double-float range', () {
      final thresholds = policy.thresholdsFor('unknown_fractal');

      expect(thresholds.cpuFallbackZoom, 1e7);
      expect(thresholds.supportsDoubleFloat, isFalse);
      expect(thresholds.shouldUseDoubleFloat(1e10), isFalse);
    });
  });

  group('DeepZoomPrecisionPolicy.decisionFor', () {
    test('exposes CPU and double-float routing from one threshold snapshot',
        () {
      final decision = policy.decisionFor(moduleId: 'mandelbrot', zoom: 1e10);

      expect(decision.moduleId, 'mandelbrot');
      expect(decision.zoom, 1e10);
      expect(decision.cpuFallbackZoom, 1e12);
      expect(decision.shouldUseDoubleFloat, isTrue);
      expect(decision.shouldUseCpuFallback, isFalse);
      expect(decision.thresholds, same(policy.thresholdsFor('mandelbrot')));
    });

    test('keeps invalid zoom samples below precision routing thresholds', () {
      for (final zoom in [double.nan, double.negativeInfinity]) {
        final decision = policy.decisionFor(
          moduleId: 'mandelbrot',
          zoom: zoom,
        );

        expect(decision.shouldUseDoubleFloat, isFalse, reason: '$zoom');
        expect(decision.shouldUseCpuFallback, isFalse, reason: '$zoom');
      }
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseCpuFallback', () {
    test('returns false for mandelbrot at zoom 1e6', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e6),
        isFalse,
      );
    });

    test('returns true for mandelbrot at zoom 1e15', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e15),
        isTrue,
      );
    });

    test('uses default threshold for unknown module', () {
      // Default threshold is 1e7; zoom just below should be false.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 9.9e6),
        isFalse,
      );
      // At or above default threshold (1e7) should be true.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 1e7),
        isTrue,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseDoubleFloat', () {
    test('returns true for mandelbrot in df2 range', () {
      // df2 range: [5e6, 1e12)
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 5e6),
        isTrue,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e10),
        isTrue,
      );
    });

    test('returns false for non-mandelbrot modules', () {
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'julia', zoom: 1e10),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'burning_ship', zoom: 1e10),
        isFalse,
      );
    });

    test('returns false below df2 lower threshold', () {
      // Below 5e6 the standard float32 shader is sufficient.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e5),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 4.9e6),
        isFalse,
      );
    });

    test('returns false at or above df2 upper threshold', () {
      // At 1e12 CPU fallback takes over; df2 should not be active.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e12),
        isFalse,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.scaledGpuIterations', () {
    test('returns base at zoom 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0),
        equals(256),
      );
    });

    test('returns base at zoom below 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 0.5),
        equals(256),
      );
    });

    test('increases with zoom depth', () {
      final atZoom1 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0);
      final atZoom1e6 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1e6);
      expect(atZoom1e6, greaterThan(atZoom1));
    });

    test('clamps to gpuMaxIterations', () {
      // Very high base + very high zoom should be clamped.
      final result = policy.scaledGpuIterations(
        baseIterations: DeepZoomPrecisionPolicy.gpuMaxIterations,
        zoom: 1e30,
      );
      expect(result, equals(DeepZoomPrecisionPolicy.gpuMaxIterations));
    });

    test('clamps low base to minimum of 4', () {
      final result = policy.scaledGpuIterations(baseIterations: 1, zoom: 1.0);
      expect(result, equals(4));
    });

    test('treats non-finite zoom values as bounded inputs', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.nan),
        equals(256),
      );
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.infinity),
        equals(DeepZoomPrecisionPolicy.gpuMaxIterations),
      );
      expect(
        policy.scaledGpuIterations(
          baseIterations: 256,
          zoom: double.negativeInfinity,
        ),
        equals(256),
      );
    });
  });

  group('DeepZoomHysteresisState', () {
    test('exposes replayable streak transitions', () {
      const initial = DeepZoomHysteresisState.initial();

      final first = initial.next(
        nextModuleId: 'julia',
        overThreshold: true,
        activationFrames: 2,
      );
      final second = first.next(
        nextModuleId: 'julia',
        overThreshold: true,
        activationFrames: 2,
      );
      final resetByZoomOut = second.next(
        nextModuleId: 'julia',
        overThreshold: false,
        activationFrames: 2,
      );
      final resetByModule = first.next(
        nextModuleId: 'mandelbrot',
        overThreshold: true,
        activationFrames: 2,
      );

      expect(first.moduleId, 'julia');
      expect(first.aboveThresholdCount, 1);
      expect(first.cpuActive, isFalse);
      expect(second.aboveThresholdCount, 2);
      expect(second.cpuActive, isTrue);
      expect(resetByZoomOut.aboveThresholdCount, 0);
      expect(resetByZoomOut.cpuActive, isFalse);
      expect(resetByModule.moduleId, 'mandelbrot');
      expect(resetByModule.aboveThresholdCount, 1);
      expect(resetByModule.cpuActive, isFalse);
    });
  });

  group('DeepZoomHysteresis', () {
    test('does not activate CPU until hysteresisFrames consecutive frames', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      // mandelbrot CPU threshold is 1e12; zoom 2e12 is above it.
      const moduleId = 'mandelbrot';
      const highZoom = 2e12;
      final frames = policy.hysteresisFrames;

      // All frames before the last should still return false.
      for (var i = 0; i < frames - 1; i++) {
        expect(
          hysteresis.update(moduleId: moduleId, zoom: highZoom),
          isFalse,
          reason: 'frame $i should not activate CPU yet',
        );
      }

      // The hysteresisFrames-th frame should activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isTrue,
      );
    });

    test('drops back to GPU immediately when zoom falls below threshold', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      const lowZoom = 1.0;
      final frames = policy.hysteresisFrames;

      // Trigger CPU mode.
      for (var i = 0; i < frames; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      // A single below-threshold update drops back to GPU.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: lowZoom),
        isFalse,
      );
    });

    test('does not carry above-threshold count across module changes', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);

      expect(
        hysteresis.update(moduleId: 'julia', zoom: 2e9),
        isFalse,
        reason: 'first Julia deep-zoom frame should only prime hysteresis',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isFalse,
        reason: 'first Mandelbrot deep-zoom frame must not inherit Julia count',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isTrue,
        reason: 'second consecutive Mandelbrot deep-zoom frame activates CPU',
      );
    });

    test('reset clears state so hysteresis counter restarts', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      final frames = policy.hysteresisFrames;

      // Build up to just before activation.
      for (var i = 0; i < frames - 1; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      hysteresis.reset();

      // After reset, the counter is zero; a single update should not activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isFalse,
      );
    });
  });
}

import 'dart:typed_data';

import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('DeepZoomPrecisionPolicy', () {
    const policy = DeepZoomPrecisionPolicy();

    test('uses per-fractal thresholds for CPU fallback', () {
      // Mandelbrot: df2 shader covers [5e6, 1e12), CPU above 1e12.
      expect(policy.thresholdFor('mandelbrot'), 1e12);
      // Escape-time fractals: GPU precision degrades around ~1e9.
      expect(policy.thresholdFor('julia'), 1e9);
      expect(policy.thresholdFor('celtic'), 1e9);
      expect(policy.thresholdFor('buffalo'), 1e9);
      expect(policy.thresholdFor('burning_ship'), 1e9);
      expect(policy.thresholdFor('tricorn'), 1e9);
      expect(policy.thresholdFor('phoenix'), 1e9);
    });

    test('provides default threshold for unlisted fractals', () {
      // Default threshold is 1e7 for safe float32 precision.
      expect(policy.thresholdFor('some_unknown'), 1e7);
    });

    test('fallback toggles at threshold', () {
      // GPU stays active for Mandelbrot until df2 upper bound.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e7),
        isFalse,
      );
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e12),
        isTrue,
      );
      // Unlisted fractals use default threshold (1e7)
      // 'some_unknown' is not in the per-module map, so it gets _defaultThreshold.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'some_unknown', zoom: 5e6),
        isFalse,
      );
      expect(
        policy.shouldUseCpuFallback(moduleId: 'some_unknown', zoom: 1e7),
        isTrue,
      );
    });

    test('auto-scales GPU iterations with zoom depth', () {
      expect(policy.scaledGpuIterations(baseIterations: 120, zoom: 1.0), 120);

      final mid = policy.scaledGpuIterations(baseIterations: 120, zoom: 1e6);
      final deep = policy.scaledGpuIterations(baseIterations: 120, zoom: 1e12);

      expect(mid, greaterThan(120));
      expect(deep, greaterThan(mid));
      expect(deep, lessThanOrEqualTo(DeepZoomPrecisionPolicy.gpuMaxIterations));

      // Clamp behavior.
      expect(
        policy.scaledGpuIterations(baseIterations: 5000, zoom: 1e30),
        DeepZoomPrecisionPolicy.gpuMaxIterations,
      );
    });
  });

  group('CPU deep-zoom quality', () {
    test('supersampling reduces grain by at least 10%', () async {
      const width = 120;
      const height = 120;

      final base = await renderCpuFrame(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.743643887, 0.131825904),
        viewZoom: 320.0,
        iterations: 320,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: width,
        height: height,
        sampleCount: 1,
      );

      final improved = await renderCpuFrame(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.743643887, 0.131825904),
        viewZoom: 320.0,
        iterations: 320,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: width,
        height: height,
        sampleCount: 4,
      );

      final baseGrain = computeGrainScore(base.rgba, width, height);
      final improvedGrain = computeGrainScore(improved.rgba, width, height);

      expect(improvedGrain, lessThan(baseGrain * 0.90));
    });

    test('supports celtic and buffalo formulas in CPU path', () async {
      final celtic = await renderCpuFrame(
        moduleId: 'celtic',
        viewPan: Vector2(-0.45, 0.22),
        viewZoom: 90.0,
        iterations: 280,
        bailout: 4.0,
        juliaC: Vector2.zero(),
        width: 64,
        height: 64,
      );

      final buffalo = await renderCpuFrame(
        moduleId: 'buffalo',
        viewPan: Vector2(-0.35, 0.3),
        viewZoom: 90.0,
        iterations: 280,
        bailout: 4.0,
        juliaC: Vector2.zero(),
        width: 64,
        height: 64,
      );

      expect(celtic.rgba.length, 64 * 64 * 4);
      expect(buffalo.rgba.length, 64 * 64 * 4);

      bool hasVariation(Uint8List rgba) {
        final first = rgba[0];
        for (final v in rgba) {
          if (v != first) return true;
        }
        return false;
      }

      expect(hasVariation(celtic.rgba), isTrue);
      expect(hasVariation(buffalo.rgba), isTrue);
    });
  });
}

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
import 'package:flutter_fractals/features/renderer/backend_policy.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  const policy = RendererBackendPolicy();

  // Helper to build a standard 2D auto input with overrides.
  BackendPolicyInput buildInput({
    bool isAndroid = false,
    bool isWeb = false,
    bool isEmulator = false,
    RendererBackendMode userMode = RendererBackendMode.auto,
    bool gpuHealthFailed = false,
    bool deepZoomNeedsCpu = false,
    FractalDimension dimension = FractalDimension.twoD,
  }) {
    return BackendPolicyInput(
      isAndroid: isAndroid,
      isWeb: isWeb,
      isEmulator: isEmulator,
