import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/gpu_gradient_module.dart';
import 'package:flutter_fractals/core/modules/gpu_sampler_diag_module.dart';
import 'package:flutter_fractals/core/modules/hydrogen_orbital_module.dart';
import 'package:flutter_fractals/core/modules/julia_dual_module.dart';
import 'package:flutter_fractals/core/modules/julia_module.dart';
import 'package:flutter_fractals/core/modules/mandelbox_module.dart';
import 'package:flutter_fractals/core/modules/mandelbulb_module.dart';
import 'package:flutter_fractals/core/modules/nova_module.dart';
import 'package:flutter_fractals/core/modules/phoenix_module.dart';
import 'package:flutter_fractals/core/modules/test_shaders_module.dart';

/// Registry of all available fractal modules.
///
/// ## Architecture (post-refactor)
///
/// Most 2D escape-time fractals are built **declaratively** from
/// [EscapeTimeConfig] entries in `builders/escape_time/catalog.dart`.
/// Adding a new escape-time fractal = one config entry + one .frag shader.
///
/// Fractals with **custom parameters** (Julia seeds, Phoenix p/q, 3D rotation)
/// still use dedicated builder functions.
///
/// ## How to add a new fractal
///
/// **Standard escape-time (iterations + bailout + color):**
/// 1. Write shader following standard uniform layout (see builders/escape_time/builder.dart)
/// 2. Add `EscapeTimeConfig(...)` to `builders/escape_time/catalog.dart`
/// 3. Register shader in `pubspec.yaml`
/// 4. Done!
///
/// **Custom params or non-escape-time:**
/// 1. Create a `buildXxxModule()` function
/// 2. Add it to [_customModules] below
///
/// {@category Modules}
class ModuleRegistry {
  /// All available fractal modules (built lazily on first access).
  late final List<FractalModule> modules = _buildAll();

  /// Creates the registry.
  ModuleRegistry();

  /// Look up a module by [id]. Throws if not found.
  FractalModule byId(String id) {
    return modules.firstWhere((m) => m.id == id);
  }

  static List<FractalModule> _buildAll() {
    // IDs already in the escape-time catalog (built declaratively).
    // Defensive de-duplication keeps registry stable even if the catalog
    // accidentally contains repeated ids.
    final catalogModules = _dedupeById(buildEscapeTimeCatalogModules());
    final catalogIds = catalogModules.map((m) => m.id).toSet();

    // Custom modules with special params/uniforms
    final customModules = <FractalModule>[
      // Julia needs extra seed params (cx, cy)
      if (!catalogIds.contains('julia')) buildJuliaModule(),
      // Julia Dual: side-by-side Mandelbrot + Julia viewer
      if (!catalogIds.contains('julia_dual')) buildJuliaDualModule(),
      // Phoenix needs extra (p, q) params
      if (!catalogIds.contains('phoenix')) buildPhoenixModule(),
      // Nova needs relaxation param instead of bailout
      if (!catalogIds.contains('nova')) buildNovaModule(),
      // Mandelbulb is 3D with rotation uniforms
      if (!catalogIds.contains('mandelbulb')) buildMandelbulbModule(),
      // Mandelbox is 3D with box-fold + sphere-fold DE
      if (!catalogIds.contains('mandelbox')) buildMandelboxModule(),
      // Hydrogen orbital is a volumetric density renderer with custom controls.
      if (!catalogIds.contains('hydrogen_orbital'))
        buildHydrogenOrbitalModule(),
    ];

    // Diagnostics (debug only, always last)
    final diagModules = kDebugMode
        ? [
            testAlwaysRedModule,
            testUniformOnlyModule,
            testMinimalModule,
            testGlFragCoordModule,
            testFlutterCoordModule,
            buildGpuGradientModule(),
            buildGpuSamplerDiagModule(),
          ]
        : <FractalModule>[];

    // Merge: catalog first (Mandelbrot at top), then custom, then diag.
    // Insert Julia after Mandelbrot, Phoenix after Burning Ship for UX order.
    final result = <FractalModule>[];

    // Find key positions for insertion
    final mandelbrotIdx =
        catalogModules.indexWhere((m) => m.id == 'mandelbrot');
    final burningShipIdx =
        catalogModules.indexWhere((m) => m.id == 'burning_ship');
    final novaJuliaIdx = catalogModules.indexWhere((m) => m.id == 'nova_julia');

    for (int i = 0; i < catalogModules.length; i++) {
      // Insert Nova right before Nova Julia
      if (i == novaJuliaIdx) {
        final nova = customModules.where((m) => m.id == 'nova');
        result.addAll(nova);
      }
      result.add(catalogModules[i]);
      // Insert Julia and Julia Dual right after Mandelbrot
      if (i == mandelbrotIdx) {
        final julia = customModules.where((m) => m.id == 'julia');
        result.addAll(julia);
        final juliaDual = customModules.where((m) => m.id == 'julia_dual');
        result.addAll(juliaDual);
      }
      // Insert Phoenix right after Burning Ship
      if (i == burningShipIdx) {
        final phoenix = customModules.where((m) => m.id == 'phoenix');
        result.addAll(phoenix);
      }
    }

    // Add remaining custom modules not yet inserted
    for (final m in customModules) {
      if (!result.any((r) => r.id == m.id)) {
        result.add(m);
      }
    }

    // 3D ray-marched catalog modules (KIFS, Quaternion, exotic)
    final raymarched3DModules = buildRaymarched3DCatalogModules();
    result.addAll(raymarched3DModules);

    result.addAll(diagModules);
    // Keep later modules when ids collide so purpose-built 3D catalog entries
    // can replace older placeholder escape-time variants with the same id.
    return _dedupeById(result, preferLast: true);
  }

  static List<FractalModule> _dedupeById(
    List<FractalModule> modules, {
    bool preferLast = false,
  }) {
    if (preferLast) {
      final seen = <String>{};
      final reversedUnique = <FractalModule>[];
      for (final module in modules.reversed) {
        if (seen.add(module.id)) {
          reversedUnique.add(module);
        }
      }
      return reversedUnique.reversed.toList(growable: false);
    }

    final seen = <String>{};
    final unique = <FractalModule>[];
    for (final module in modules) {
      if (seen.add(module.id)) {
        unique.add(module);
      }
    }
    return unique;
  }
}

import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

/// Replayable viewport dimensions for CPU coordinate mapping.
///
/// Render requests should provide positive dimensions. When a direct mapping
/// caller passes invalid dimensions, fall back to a square viewport instead of
/// leaking zero/negative aspect ratios into fractal coordinates.
final class CpuViewportDimensions {
  const CpuViewportDimensions({required this.width, required this.height});

  final int width;
  final int height;

  factory CpuViewportDimensions.fromSize({
    required int width,
    required int height,
  }) {
    if (width <= 0 || height <= 0) {
      return const CpuViewportDimensions(width: 1, height: 1);
    }
    return CpuViewportDimensions(width: width, height: height);
  }

  double get aspect => width / height;
}

/// Replayable CPU viewport center.
///
/// The controller normally provides finite pan coordinates, but CPU fallback
/// code also accepts replayed/isolate scalar requests. Non-finite pan samples
/// must not poison every formula coordinate with NaN/Infinity, so they adopt
/// the origin instead.
final class CpuViewportCenter {
  const CpuViewportCenter({required this.x, required this.y});

  final double x;
  final double y;

  factory CpuViewportCenter.fromScalars({
    required double panX,
    required double panY,
  }) {
    return CpuViewportCenter(
      x: normalizeCoordinate(panX),
      y: normalizeCoordinate(panY),
    );
  }

  static double normalizeCoordinate(double value) {
    return value.isFinite ? value : 0.0;
  }
}

/// Explicit dimensions contract for CPU render work.
final class CpuRenderDimensions {
  const CpuRenderDimensions({required this.width, required this.height});

  final int width;
  final int height;

  void validate() {
    if (width <= 0 || height <= 0) {
      throw ArgumentError.value(
        (width, height),
        'full viewport',
        'must be positive',
      );
    }
  }
}

/// Explicit bounds contract for a CPU render tile inside a full viewport.
final class CpuRenderRect {
  const CpuRenderRect({
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
  });

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (w <= 0 || h <= 0) {
      throw ArgumentError.value((w, h), 'tile size', 'must be positive');
    }
    if (x0 < 0 || y0 < 0 || x0 + w > fullWidth || y0 + h > fullHeight) {
      throw ArgumentError.value(
        (x0, y0, w, h),
        'tile rect',
        'must be within the full viewport',
      );
    }
  }
}

/// Explicit point contract for a CPU pixel sample inside a full viewport.
final class CpuRenderSamplePoint {
  const CpuRenderSamplePoint({
    required this.fullWidth,
    required this.fullHeight,
    required this.x,
    required this.y,
  });

  final int fullWidth;
  final int fullHeight;
  final int x;
  final int y;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (x < 0 || y < 0 || x >= fullWidth || y >= fullHeight) {
      throw ArgumentError.value(
        (x, y),
        'sample coordinate',
        'must be inside the full viewport',
      );
    }
  }
}

/// Shared CPU-render viewport mapping.
///
/// Pixel coordinates are edge-inclusive for iteration buffers, preserving the
/// existing scalar-field/golden contract. Subpixel sample coordinates are
/// center-of-pixel positions and must stay inside the same [-1, 1] viewport.
final class CpuViewportMapping {
  final double centerX;
  final double centerY;
  final double scale;
  final double aspect;

  CpuViewportMapping({
    required Vector2 viewPan,
    required double viewZoom,
    required int width,
    required int height,
  }) : this.fromScalars(
          panX: viewPan.x,
          panY: viewPan.y,
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping.fromScalars({
    required double panX,
    required double panY,
    required double viewZoom,
    required int width,
    required int height,
  }) : this._(
          center: CpuViewportCenter.fromScalars(panX: panX, panY: panY),
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping._({
    required CpuViewportCenter center,
    required double viewZoom,
    required int width,
    required int height,
  })  : centerX = center.x,
        centerY = center.y,
        scale = 1.5 / normalizeZoom(viewZoom),
        aspect = CpuViewportDimensions.fromSize(
          width: width,
          height: height,
        ).aspect;

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return 1.0;
    return zoom;
  }

  double normalizedPixel(int pixel, int extent) {
    if (extent <= 1) return 0.0;
    return (pixel / (extent - 1)) * 2.0 - 1.0;
  }

  double normalizedSample({
    required int pixel,
    required int extent,
    required int sample,
    required int samplesPerAxis,
  }) {
    final safeSamples = samplesPerAxis <= 0 ? 1 : samplesPerAxis;
    final safeSample = sample.clamp(0, safeSamples - 1).toInt();
    return normalizedSampleOffset(
      pixel: pixel,
      extent: extent,
      sampleOffset: (safeSample + 0.5) / safeSamples,
    );
  }

  double normalizedSampleOffset({
    required int pixel,
    required int extent,
    required double sampleOffset,
  }) {
    if (extent <= 1) return 0.0;
    final safePixel = pixel.clamp(0, extent - 1).toInt();
    final safeOffset =
        sampleOffset.isNaN ? 0.5 : sampleOffset.clamp(0.0, 1.0).toDouble();
    final subPixel = safePixel + safeOffset;
    return (subPixel / extent) * 2.0 - 1.0;
  }

  (double x, double y) coordinate({required double nx, required double ny}) {
    return (centerX + nx * scale * aspect, centerY + ny * scale);
  }
}

/// Replayable CPU anti-aliasing grid derived from a requested sample count.
///
/// The CPU renderer samples a square grid, so non-square requests are rounded up
/// to the next square grid instead of silently dropping requested samples.
final class CpuSampleGrid {
  CpuSampleGrid.fromRequestedCount(int requestedCount)
      : this._(
          requestedCount: requestedCount,
          samplesPerAxis: _samplesPerAxisFor(requestedCount),
        );

  const CpuSampleGrid._({
    required this.requestedCount,
    required this.samplesPerAxis,
  });

  final int requestedCount;
  final int samplesPerAxis;

  int get totalSamples => samplesPerAxis * samplesPerAxis;

  bool get wasRoundedUp => totalSamples > math.max(1, requestedCount);

  static int _samplesPerAxisFor(int requestedCount) {
    if (requestedCount <= 0) return 1;
    return math.max(1, math.sqrt(requestedCount).ceil());
  }
}

